/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007;
    const MAX_VAL = 5000;
    const MAX_DIGIT_SUM = 50;

    /**
     * Precompute all numbers <= MAX_VAL that have a specific digit sum.
     * Since MAX_VAL is small (5000), we can iterate and precalculate.
     * results[s] will be an array of numbers <= 5000 whose digit sum is s.
     */
    const results = Array(MAX_DIGIT_SUM + 1).fill(0).map(() => []);

    function calculateDigitSum(n) {
        let sum = 0;
        let strN = String(n);
        for (let i = 0; i < strN.length; i++) {
            sum += parseInt(strN[i]);
        }
        return sum;
    }

    for (let i = 0; i <= MAX_VAL; i++) {
        const ds = calculateDigitSum(i);
        if (ds <= MAX_DIGIT_SUM) {
            results[ds].push(i);
        }
    }

    /**
     * dp[i][j] = number of valid prefixes of length i, where the i-th element is j.
     * Since the values can be large, we will use a different DP state:
     * dp[i] = A map or object where keys are the possible values for arr[i], 
     * and values are the count of ways to form a valid prefix ending at that value.
     * 
     * Given the constraints (N up to 1000, values up to 5000), storing counts 
     * based on the value might be too sparse/large.
     * 
     * Let's rethink the DP based on the structure:
     * DP[i][prev_val] = number of valid arrays of length i ending with arr[i] = prev_val.
     * This is too large because prev_val can be up to 5000.
     * 
     * Since we only care about the *number* of ways, and the transition depends only on the *value* of the previous element,
     * we can use DP on the index i, and transition based on the set of possible values.
     * 
     * Let S[i] be the set of all valid numbers for digitSum[i] (i.e., results[digitSum[i]]).
     * Let dp[i][j] be the number of valid arrays of length i+1 (0-indexed) such that arr[i] = j, where j must be in S[i].
     * 
     * Base Case (i = 0):
     * dp[0][j] = 1 for all j in S[0].
     * 
     * Transition (i > 0):
     * dp[i][j] = sum(dp[i-1][k]) for all k in S[i-1] such that k <= j.
     * 
     * Final Answer:
     * Sum(dp[n-1][j]) for all j in S[n-1].
     */

    const N = digitSum.length;

    // dp[i] is an object mapping: value_k -> count
    // count is the number of valid sequences of length i+1 ending in value_k.
    let dp = new Array(N);

    // --- Base Case i = 0 ---
    const S0 = results[digitSum[0]];
    dp[0] = new Map();
    for (const val of S0) {
        dp[0].set(val, 1);
    }

    // --- Transitions i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const Si = results[digitSum[i]];
        const Si_minus_1 = results[digitSum[i - 1]];
        dp[i] = new Map();

        // For each potential value j for arr[i]
        for (const j of Si) {
            let currentCount = 0;

            // Sum up counts from previous valid elements k <= j
            for (const k of Si_minus_1) {
                if (k <= j) {
                    const countK = dp[i - 1].get(k) || 0;
                    currentCount = (currentCount + countK) % MOD;
                }
            }

            if (currentCount > 0) {
                dp[i].set(j, currentCount);
            }
        }
    }

    // --- Final Result ---
    let totalCount = 0;
    if (N > 0) {
        const lastDP = dp[N - 1];
        for (const count of lastDP.values()) {
            totalCount = (totalCount + count) % MOD;
        }
    }

    return totalCount;
}

