fn solve(digitSum: Vec<i64>) -> i64 {
    let mod_val: i64 = 1_000_000_007;
    let max_val: i64 = 5000;
    let max_digit_sum: i64 = 50;

    // Helper function to calculate the digit sum of a number
    let calculate_digit_sum = |n: i64| -> i64 {
        let mut sum = 0;
        let mut num = n;
        while num > 0 {
            sum += (num % 10) as i64;
            num /= 10;
        }
        sum
    };

    // results[s] will be a vector of numbers <= 5000 whose digit sum is s.
    let mut results: Vec<Vec<i64>> = vec![Vec::new(); (max_digit_sum + 1) as usize];

    for i in 0..=max_val {
        let ds = calculate_digit_sum(i);
        if ds <= max_digit_sum {
            results[ds as usize].push(i);
        }
    }

    let n = digitSum.len();
    if n == 0 {
        return 0;
    }

    // dp[i] stores a HashMap: value_k -> count
    // count is the number of valid sequences of length i+1 ending in value_k.
    // Since N is up to 1000, we only need the DP state from the previous step.
    // dp_prev: HashMap<i64, i64> for DP[i-1]
    // dp_curr: HashMap<i64, i64> for DP[i]

    // --- Base Case i = 0 ---
    let mut dp_prev: std::collections::HashMap<i64, i64> = std::collections::HashMap::new();
    let s0_sum = digitSum[0] as usize;
    for &val in results[s0_sum] {
        dp_prev.insert(val, 1);
    }

    // --- Transitions i = 1 to N-1 ---
    for i in 1..n {
        let mut dp_curr: std::collections::HashMap<i64, i64> = std::collections::HashMap::new();

        let si_sum = digitSum[i] as usize;
        let si_minus_1_sum = digitSum[i - 1] as usize;

        let si = &results[si_sum];

        // For each potential value j for arr[i]
        for &j in si {
            let mut current_count: i64 = 0;

            // Sum up counts from previous valid elements k <= j
            // We iterate over the keys (k) in dp_prev
            for (&k, &count_k) in dp_prev.iter() {
                if k <= j {
                    current_count = (current_count + count_k) % mod_val;
                }
            }

            if current_count > 0 {
                dp_curr.insert(j, current_count);
            }
        }

        dp_prev = dp_curr;

        // Optimization/Check: if dp_prev becomes empty, no solution exists.
        if dp_prev.is_empty() {
            return 0;
        }
    }

    // --- Final Result ---
    let mut total_count: i64 = 0;
    for &count in dp_prev.values() {
        total_count = (total_count + count) % mod_val;
    }

    total_count
}
